import { useState, useEffect, useCallback, useMemo } from 'react';
import { getApiBase } from '../utils/platform';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './OrderFlowPage.module.css';

const POPULAR = ['AAPL', 'MSFT', 'NVDA', 'AMZN', 'GOOGL', 'META', 'TSLA', 'SPY', 'QQQ', 'AMD'];

function VolumeProfileBar({ price, buyVol, sellVol, maxVol, isCurrentPrice }) {
  const total = buyVol + sellVol;
  const buyPct = total > 0 ? (buyVol / total) * 100 : 50;
  const width = total > 0 ? (total / maxVol) * 100 : 0;

  return (
    <div className={isCurrentPrice ? s.vpBarRowCurrent : s.vpBarRow}>
      <span className={isCurrentPrice ? s.vpPriceCurrent : s.vpPrice}>
        ${price.toFixed(2)}
      </span>
      <div className={s.vpBarTrack}>
        <div className={s.vpBarBuy} style={{ width: `${width * buyPct / 100}%` }} />
        <div className={s.vpBarSell} style={{ width: `${width * (100 - buyPct) / 100}%` }} />
      </div>
      <span className={s.vpVolLabel}>
        {total >= 1000 ? `${(total / 1000).toFixed(0)}K` : total}
      </span>
    </div>
  );
}

function DeltaChart({ data, height = 120 }) {
  if (!data || data.length === 0) return null;
  const maxAbs = Math.max(...data.map(d => Math.abs(d.delta)), 1);
  const w = 600;
  const barW = Math.max(2, (w / data.length) - 1);
  const mid = height / 2;

  return (
    <svg viewBox={`0 0 ${w} ${height}`} style={{ width: '100%', height }}>
      <line x1="0" y1={mid} x2={w} y2={mid}
        stroke="var(--color-border, rgba(255,255,255,0.06))" strokeWidth="1" />
      {data.map((d, i) => {
        const barH = (Math.abs(d.delta) / maxAbs) * (height / 2 - 4);
        const isPos = d.delta >= 0;
        const x = i * (w / data.length);
        return (
          <rect key={i} x={x} y={isPos ? mid - barH : mid} width={barW} height={barH}
            fill={isPos
              ? 'color-mix(in srgb, var(--color-green, #22C55E) 67%, transparent)'
              : 'color-mix(in srgb, var(--color-red, #EF4444) 67%, transparent)'}
            rx="1" />
        );
      })}
    </svg>
  );
}

function CumulativeDeltaChart({ data, height = 100 }) {
  if (!data || data.length < 2) return null;
  const cumDeltas = [];
  let cum = 0;
  data.forEach(d => { cum += d.delta; cumDeltas.push(cum); });

  const min = Math.min(...cumDeltas);
  const max = Math.max(...cumDeltas);
  const range = max - min || 1;
  const w = 600;

  const points = cumDeltas.map((v, i) => {
    const x = (i / (cumDeltas.length - 1)) * w;
    const y = height - 4 - ((v - min) / range) * (height - 8);
    return `${x},${y}`;
  }).join(' ');

  const lastVal = cumDeltas[cumDeltas.length - 1];
  const color = lastVal >= 0
    ? 'var(--color-green, #22C55E)'
    : 'var(--color-red, #EF4444)';

  return (
    <svg viewBox={`0 0 ${w} ${height}`} style={{ width: '100%', height }}>
      <defs>
        <linearGradient id="cumDeltaGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.3" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      <polyline fill="none" stroke={color} strokeWidth="2" points={points} />
      <polygon fill="url(#cumDeltaGrad)"
        points={`0,${height} ${points} ${w},${height}`} />
    </svg>
  );
}

export default function OrderFlowPage() {
  usePageTitle('Order Flow');
  const [symbol, setSymbol] = useState('SPY');
  const [inputValue, setInputValue] = useState('SPY');
  const [ohlcv, setOhlcv] = useState(null);
  const [micro, setMicro] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchData = useCallback(async (sym) => {
    setLoading(true);
    setError(null);
    try {
      const [ohlcvRes, microRes] = await Promise.allSettled([
        fetch(`${getApiBase()}/charts/ohlcv/${sym}?bars=60`).then(r => r.json()),
        fetch(`${getApiBase()}/microstructure/${sym}`).then(r => r.json()),
      ]);
      if (ohlcvRes.status === 'fulfilled') setOhlcv(ohlcvRes.value);
      if (microRes.status === 'fulfilled' && !microRes.value?.error) setMicro(microRes.value);
      else setMicro(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(symbol); }, [symbol, fetchData]);

  const handleSubmit = (e) => {
    e.preventDefault();
    const v = inputValue.trim().toUpperCase();
    if (v) setSymbol(v);
  };

  // Derive order flow data from OHLCV (simulated — real footprint needs tick data)
  const flowData = useMemo(() => {
    const bars = ohlcv?.bars || ohlcv?.data || ohlcv || [];
    if (!Array.isArray(bars) || bars.length === 0) return { profile: [], deltas: [], stats: {} };

    const deltas = bars.map(bar => {
      const o = bar.open || bar.Open || 0;
      const c = bar.close || bar.Close || 0;
      const h = bar.high || bar.High || 0;
      const l = bar.low || bar.Low || 0;
      const v = bar.volume || bar.Volume || 0;
      const range = h - l || 1;
      const delta = ((c - o) / range) * v;
      const buyVol = (v + Math.abs(delta)) / 2;
      const sellVol = v - buyVol;
      return { delta: Math.round(delta), buyVol: Math.round(buyVol), sellVol: Math.round(sellVol), price: c, volume: v };
    });

    const priceVolMap = {};
    deltas.forEach(d => {
      const level = Math.round(d.price * 2) / 2;
      if (!priceVolMap[level]) priceVolMap[level] = { buyVol: 0, sellVol: 0 };
      priceVolMap[level].buyVol += d.buyVol;
      priceVolMap[level].sellVol += d.sellVol;
    });

    const profile = Object.entries(priceVolMap)
      .map(([price, vols]) => ({ price: parseFloat(price), ...vols }))
      .sort((a, b) => b.price - a.price)
      .slice(0, 20);

    const totalBuy = deltas.reduce((s, d) => s + d.buyVol, 0);
    const totalSell = deltas.reduce((s, d) => s + d.sellVol, 0);
    const netDelta = deltas.reduce((s, d) => s + d.delta, 0);
    const lastPrice = deltas[deltas.length - 1]?.price || 0;

    return {
      profile,
      deltas,
      stats: {
        totalBuy, totalSell, netDelta, lastPrice,
        buyPressure: totalBuy / (totalBuy + totalSell || 1),
        avgDelta: netDelta / (deltas.length || 1),
      },
    };
  }, [ohlcv]);

  const maxProfileVol = Math.max(...flowData.profile.map(p => p.buyVol + p.sellVol), 1);

  return (
    <div className={s.pageRoot}>
      <h1 className={s.title}>Order Flow Analysis</h1>
      <p className={s.subtitle}>
        Volume profile, delta chart, cumulative delta, and order flow metrics
      </p>

      {/* Symbol selector */}
      <div className={s.selectorRow}>
        <form onSubmit={handleSubmit} className={s.searchForm}>
          <input value={inputValue} onChange={e => setInputValue(e.target.value.toUpperCase())}
            placeholder="Symbol..." className={s.symbolInput} />
          <button type="submit" disabled={loading} className={s.analyzeBtn}>
            {loading ? 'Loading...' : 'Analyze'}
          </button>
        </form>
        <div className={s.popularRow}>
          {POPULAR.map(sym => (
            <button key={sym} onClick={() => { setInputValue(sym); setSymbol(sym); }}
              className={symbol === sym ? s.popularBtnActive : s.popularBtn}>
              {sym}
            </button>
          ))}
        </div>
      </div>

      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorText}>{error}</div>
        </GlassPanel>
      )}

      {loading && (
        <div className={s.loadingText}>Loading order flow for {symbol}...</div>
      )}

      {!loading && flowData.deltas.length > 0 && (
        <>
          {/* Stats row */}
          <div className={s.statsGrid}>
            <StatCard label="Last Price" value={`$${flowData.stats.lastPrice.toFixed(2)}`}
              color="var(--color-textPrimary, #E8ECF1)" />
            <StatCard label="Net Delta" value={flowData.stats.netDelta.toLocaleString()}
              color={flowData.stats.netDelta >= 0 ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)'}
              trend={flowData.stats.netDelta >= 0 ? 'up' : 'down'} />
            <StatCard label="Buy Pressure" value={`${(flowData.stats.buyPressure * 100).toFixed(1)}%`}
              color={flowData.stats.buyPressure >= 0.55 ? 'var(--color-green, #22C55E)' : flowData.stats.buyPressure <= 0.45 ? 'var(--color-red, #EF4444)' : 'var(--color-amber, #F59E0B)'} />
            <StatCard label="Avg Delta/Bar" value={Math.round(flowData.stats.avgDelta).toLocaleString()}
              color={flowData.stats.avgDelta >= 0 ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)'} />
            {micro && <StatCard label="VPIN" value={micro.vpin?.toFixed(4) || '--'} color="var(--color-red, #EF4444)" />}
            {micro && <StatCard label="Toxicity" value={micro.order_flow_toxicity?.toFixed(4) || '--'} color="var(--color-amber, #F59E0B)" />}
          </div>

          <div className={s.twoColGrid}>
            {/* Volume Profile */}
            <GlassPanel>
              <div className={s.sectionTitle}>Volume Profile</div>
              <div className={s.legendRow}>
                <span className={s.legendItem}>
                  <span className={s.legendDotBuy} /> Buy
                </span>
                <span className={s.legendItem}>
                  <span className={s.legendDotSell} /> Sell
                </span>
              </div>
              {flowData.profile.map(p => (
                <VolumeProfileBar key={p.price} price={p.price} buyVol={p.buyVol} sellVol={p.sellVol}
                  maxVol={maxProfileVol} isCurrentPrice={Math.abs(p.price - flowData.stats.lastPrice) < 0.5} />
              ))}
            </GlassPanel>

            {/* Delta & Cumulative */}
            <div className={s.deltaColumn}>
              <GlassPanel>
                <div className={s.sectionTitle}>Delta Chart</div>
                <DeltaChart data={flowData.deltas} />
              </GlassPanel>
              <GlassPanel>
                <div className={s.sectionTitle}>Cumulative Delta</div>
                <CumulativeDeltaChart data={flowData.deltas} />
              </GlassPanel>
            </div>
          </div>

          {/* Microstructure metrics */}
          {micro && (
            <GlassPanel>
              <div className={s.sectionTitle}>Microstructure Metrics</div>
              <div className={s.microGrid}>
                {[
                  { label: 'Bid-Ask Spread', value: `${micro.bid_ask_spread_bps?.toFixed(1) || '--'} bps`, color: 'var(--color-blue, #60A5FA)' },
                  { label: 'Effective Spread', value: `${micro.effective_spread_bps?.toFixed(1) || '--'} bps`, color: 'var(--color-blue, #60A5FA)' },
                  { label: 'Kyle Lambda', value: micro.kyle_lambda?.toFixed(6) || '--', color: 'var(--color-purple, #A78BFA)' },
                  { label: 'Vol Imbalance', value: micro.volume_imbalance?.toFixed(3) || '--', color: micro.volume_imbalance > 0 ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)' },
                  { label: 'Price Impact', value: `${micro.price_impact_bps?.toFixed(1) || '--'} bps`, color: 'var(--color-amber, #F59E0B)' },
                  { label: 'Amihud', value: micro.amihud_illiquidity?.toFixed(6) || '--', color: 'var(--color-amber, #F59E0B)' },
                ].map(m => (
                  <div key={m.label} className={s.microCard}>
                    <div className={s.microLabel}>{m.label}</div>
                    <div className={s.microValue} style={{ color: m.color }}>{m.value}</div>
                  </div>
                ))}
              </div>
            </GlassPanel>
          )}
        </>
      )}

      {!loading && flowData.deltas.length === 0 && !error && (
        <GlassPanel className={s.emptyPanel}>
          <div className={s.emptyText}>Enter a symbol to analyze its order flow</div>
        </GlassPanel>
      )}
    </div>
  );
}
